import os
import shutil
import subprocess
import sys

def backup_directory(directory_path, archive_format):
    if not os.path.isdir(directory_path):
        print("Invalid directory path.")
        return

    base_name = os.path.basename(os.path.normpath(directory_path))
    archive_name = f"{base_name}_backup"

    if archive_format == 'tar.gz':
        shutil.make_archive(archive_name, 'gztar', directory_path)
    elif archive_format == 'tar.bz2':
        shutil.make_archive(archive_name, 'bztar', directory_path)
    elif archive_format == 'zip':
        shutil.make_archive(archive_name, 'zip', directory_path)
    elif archive_format == '7z':
        if shutil.which('7z') is not None:
            subprocess.run(['7z', 'a', f"{archive_name}.7z", directory_path], check=True)
        else:
            print("7z command not found. Please install p7zip.")
    else:
        print("Unsupported archive format. Please use 'tar.gz', 'tar.bz2', 'zip', or '7z'.")

if __name__ == "__main__":
    if len(sys.argv) != 3:
        print("Usage: python backup_script.py <directory_path> <archive_format>")
    else:
        backup_directory(sys.argv[1], sys.argv[2])